macOS ulimits maxfiles
obsidian.nvim rename 할 때 too many open files 오류 발생해서 해결하려고 늘림

관련 이슈

안됨
ulimit -Sa
# core file size              (blocks, -c) 0
# data seg size               (kbytes, -d) unlimited
# file size                   (blocks, -f) unlimited
# max locked memory           (kbytes, -l) unlimited
# max memory size             (kbytes, -m) unlimited
# open files                          (-n) 256
# pipe size                (512 bytes, -p) 1
# stack size                  (kbytes, -s) 8176
# cpu time                   (seconds, -t) unlimited
# max user processes                  (-u) 10666
# virtual memory              (kbytes, -v) unlimited
ulimit -n 65536
ulimit -Sa
# core file size              (blocks, -c) 0
# data seg size               (kbytes, -d) unlimited
# file size                   (blocks, -f) unlimited
# max locked memory           (kbytes, -l) unlimited
# max memory size             (kbytes, -m) unlimited
# open files                          (-n) 65536
# pipe size                (512 bytes, -p) 1
# stack size                  (kbytes, -s) 8176
# cpu time                   (seconds, -t) unlimited
# max user processes                  (-u) 10666
# virtual memory              (kbytes, -v) unlimited
sudo launchctl limit maxfiles
#         maxfiles    256            unlimited
sudo launchctl limit maxfiles 10240 unlimited
sudo launchctl limit maxfiles
#         maxfiles    10240          unlimited
해결책
sudo nvim /Library/LaunchDaemons/limit.maxfiles.plist
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;
&lt;!DOCTYPE plist PUBLIC &quot;-//Apple//DTD PLIST 1.0//EN&quot; &quot;www.apple.com/DTDs/PropertyList-1.0.dtd&quot;&gt;
&lt;plist version=&quot;1.0&quot;&gt;
  &lt;dict&gt;
    &lt;key&gt;Label&lt;/key&gt;
    &lt;string&gt;limit.maxfiles&lt;/string&gt;
    &lt;key&gt;ProgramArguments&lt;/key&gt;
    &lt;array&gt;
      &lt;string&gt;launchctl&lt;/string&gt;
      &lt;string&gt;limit&lt;/string&gt;
      &lt;string&gt;maxfiles&lt;/string&gt;
      &lt;string&gt;10240&lt;/string&gt;
      &lt;string&gt;10240&lt;/string&gt;
    &lt;/array&gt;
    &lt;key&gt;RunAtLoad&lt;/key&gt;
    &lt;true /&gt;
  &lt;/dict&gt;
&lt;/plist&gt;
